import React, { useState, useEffect, useRef } from 'react';

export default function Header({
  user,
  onLogout,
  onSearchChange,
  switchView,
}) {
  const [dropdownOpen, setDropdownOpen] = useState(false);
  const [searchValue, setSearchValue] = useState('');
  const dropdownRef = useRef(null);

  useEffect(() => {
    function handleClickOutside(event) {
      if (
        dropdownRef.current &&
        !dropdownRef.current.contains(event.target)
      ) {
        setDropdownOpen(false);
      }
    }

    document.addEventListener('mousedown', handleClickOutside);

    return () =>
      document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const getInitials = (name) => {
    if (!name) return 'U';

    return name
      .split(' ')
      .map((n) => n[0])
      .join('')
      .substring(0, 2)
      .toUpperCase();
  };

  const handleSearchInput = (e) => {
    const value = e.target.value;
    setSearchValue(value);
    onSearchChange(value);
  };

  return (
    <header className="h-16 border-b border-brand-border/60 bg-[#0d0e11]/80 backdrop-blur px-6 flex items-center justify-between shrink-0">
      <div className="flex items-center gap-8">
        <span className="text-xl font-bold tracking-tight text-white select-none">
          buzzvel
        </span>

        <div className="hidden sm:flex items-center gap-6">
          <button
            onClick={() => switchView('overview')}
            className="text-xs text-white border-b-2 border-transparent pb-[22px] mt-[20px] font-medium hover:border-brand-coral transition"
          >
            Overview
          </button>

          <button
            onClick={() => switchView('create')}
            className="text-xs text-white border-b-2 border-transparent pb-[22px] mt-[20px] font-medium hover:border-brand-coral transition"
          >
            Requests
          </button>
        </div>
      </div>

      <div className="flex items-center gap-4">
        <div className="relative hidden sm:block">
          <input
            type="text"
            placeholder="Search transactions..."
            value={searchValue}
            onChange={handleSearchInput}
            className="w-56 bg-brand-input border border-brand-border/60 hover:border-brand-border focus:border-brand-coral/40 rounded-lg py-1.5 pl-8 pr-4 text-xs text-white placeholder-brand-text-muted/50 outline-none transition duration-200"
          />

          <svg
            className="w-3.5 h-3.5 absolute left-3 top-2.5 text-brand-text-muted/60"
            fill="none"
            stroke="currentColor"
            viewBox="0 0 24 24"
          >
            <path
              strokeLinecap="round"
              strokeLinejoin="round"
              strokeWidth="2"
              d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"
            />
          </svg>
        </div>

        <button className="relative w-8 h-8 rounded-lg bg-brand-card border border-brand-border/60 flex items-center justify-center text-brand-text-muted hover:text-white hover:border-brand-border transition cursor-pointer">
          <svg
            className="w-4 h-4"
            fill="none"
            stroke="currentColor"
            viewBox="0 0 24 24"
          >
            <path
              strokeLinecap="round"
              strokeLinejoin="round"
              strokeWidth="2"
              d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9"
            />
          </svg>

          <span className="absolute top-1.5 right-1.5 w-1.5 h-1.5 rounded-full bg-brand-coral"></span>
        </button>

        <div className="relative" ref={dropdownRef}>
          <button
            onClick={() => setDropdownOpen(!dropdownOpen)}
            className="flex items-center gap-2 py-1 px-1.5 rounded-lg border border-transparent hover:border-brand-border/60 hover:bg-brand-card transition cursor-pointer"
          >
            <div className="w-7 h-7 rounded-full bg-brand-coral/20 border border-brand-coral/40 flex items-center justify-center font-bold text-xs text-brand-coral">
              {getInitials(user?.name)}
            </div>

            <span className="text-xs font-medium text-white max-w-[100px] truncate hidden md:inline">
              {user?.name || 'User'}
            </span>

            <svg
              className="w-3.5 h-3.5 text-brand-text-muted hidden md:block"
              fill="none"
              stroke="currentColor"
              viewBox="0 0 24 24"
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth="2"
                d="M19 9l-7 7-7-7"
              />
            </svg>
          </button>

          {dropdownOpen && (
            <div className="absolute right-0 mt-2 w-48 bg-brand-card border border-brand-border rounded-lg shadow-xl py-1.5 z-40">
              <div className="px-4 py-2 border-b border-brand-border/40 mb-1">
                <p className="text-xs font-semibold text-white">
                  {user?.name || 'User Name'}
                </p>

                <p className="text-[10px] text-brand-text-muted truncate mt-0.5">
                  {user?.email || 'email@example.com'}
                </p>
              </div>

              <button
                onClick={onLogout}
                className="w-full text-left px-4 py-2 text-xs text-red-400 hover:text-red-300 hover:bg-brand-border/40 transition flex items-center gap-2 cursor-pointer"
              >


                <span>Logout</span>
              </button>
            </div>
          )}
        </div>
      </div>
    </header>
  );
}
